#include <stdio.h>
#include <math.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < Q; i++) {
        int X, L, R;
        scanf("%d %d %d", &X, &L, &R);
        int sum = 0;
        for (int j = L - 1; j < R; j++) {
            sum += ceil((double)X / A[j]);
        }
        printf("%d\n", sum);
    }
    return 0;
}

