code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        for (int i = 0; i < Q; i++) {
            int X = sc.nextInt();
            int L = sc.nextInt();
            int R = sc.nextInt();
            int sum = 0;
            for (int j = L - 1; j < R; j++) {
                sum += (int) Math.ceil((double) X / A[j]);
            }
            System.out.println(sum);
        }
    }
}

